INSERT INTO public.om_activity_years (activity_code, fiscal_year, service, appropriation, ba, sag_short_code, title, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$OM_NAVY_X_120$$, 2026, $$Navy$$, $$OM_NAVY$$, NULL, NULL, $$Department of the Navy$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$, 3C1F
                                                                     146                                                                        (Page 9 of 9)
                                                                              Department of the Navy
                                                                      FY 2026 President's Budget Submission
                                                                     Operation and Maintenance, Marine Corps
                                                                     Budget Activity: Training and Recruiting
                                                           Activity Group: Recruiting & Other Training And Education
                                                          Detail by Subactivity Group: Off-Duty and Voluntary Education
I. Description of Operations Financed:
This subactivity funds the Marine Corps' off-duty and voluntary education program which provides Marines an opportunity to enhance their careers through education programs by providing
tuition assistance support. Levels of education financed in this program are apprenticeship, vocational/technical, and college level undergraduate and graduate courses - which provide
training opportunities for Marines to improve performance and enhance professional military education. The program improves recruitment and retention (higher education levels correlate
to higher reenlistment rates) and enhances readiness (reduces disciplinary problems, increases prospects for promotion, increases Armed Services Vocational Aptitude Battery (ASVAB)
scores, and supports career progression).

II. Force Structure Summary:
Approximately 22,000 Marines participate in the off-duty and voluntary education program annually via a network of Marine Corps education offices and satellite offices.




